import{_ as l,C as i,o as d,c,E as s,w as p,j as t,a as o,ad as h}from"./chunks/framework.DdcUsuRQ.js";const w=JSON.parse('{"title":"iridis","titleTemplate":false,"description":"iridis is a browser-side palette engine that assigns your seed colors to design-system roles while enforcing WCAG or APCA contrast in OKLCH space.","frontmatter":{"title":"iridis","layout":"doc","description":"iridis is a browser-side palette engine that assigns your seed colors to design-system roles while enforcing WCAG or APCA contrast in OKLCH space.","head":[["link",{"rel":"canonical","href":"https://studnicky.github.io/iridis/"}],["meta",{"property":"og:url","content":"https://studnicky.github.io/iridis/"}],["meta",{"property":"og:title","content":"iridis"}],["meta",{"property":"og:description","content":"iridis is a browser-side palette engine that assigns your seed colors to design-system roles while enforcing WCAG or APCA contrast in OKLCH space."}],["meta",{"name":"twitter:title","content":"iridis"}],["meta",{"name":"twitter:description","content":"iridis is a browser-side palette engine that assigns your seed colors to design-system roles while enforcing WCAG or APCA contrast in OKLCH space."}],["meta",{"name":"description","content":"iridis is a browser-side palette engine that assigns your seed colors to design-system roles while enforcing WCAG or APCA contrast in OKLCH space."}],["meta",{"property":"article:modified_time","content":"2026-05-17T16:04:29.000Z"}],["meta",{"property":"article:author","content":"Andrew Studnicky"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"iridis\\",\\"item\\":\\"https://studnicky.github.io/iridis/\\"}]}"]]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1779033869000}'),g={name:"index.md"},u={style:{display:"flex",gap:"0.6rem","flex-wrap":"wrap","align-items":"center"}};function m(y,e,f,v,b,k){const r=i("PaletteCTA"),n=i("AuroraHero"),a=i("BuildPanel");return d(),c("div",null,[s(n,null,{default:p(()=>[e[2]||(e[2]=t("div",{style:{"font-size":"2.8rem","font-weight":"700","letter-spacing":"-0.025em",margin:"0 0 0.5rem",color:"var(--vp-c-text-1)"}},[t("span",{class:"iridis-brand"},"iridis")],-1)),e[3]||(e[3]=t("p",{style:{"font-size":"1.18rem",color:"var(--vp-c-text-2)","max-width":"680px",margin:"0 0 1.5rem","line-height":"1.55"}},[o(" You bring the colors you want to use and the role names your design system uses. "),t("span",{class:"iridis-brand"},"iridis"),o(" decides which color goes to which role so every accessibility constraint you declare is satisfied. ")],-1)),t("div",u,[s(r),e[0]||(e[0]=t("a",{href:"/iridis/getting-started",style:{"text-decoration":"none",padding:"0.55rem 1.2rem","border-radius":"6px",background:"color-mix(in oklch, var(--vp-c-bg) 80%, transparent)",color:"var(--vp-c-text-1)",border:"1px solid var(--vp-c-divider)","font-weight":"500","font-size":"0.95rem","backdrop-filter":"blur(8px)"}},"For developers",-1)),e[1]||(e[1]=t("a",{href:"https://github.com/Studnicky/iridis",style:{"text-decoration":"none",padding:"0.55rem 1.2rem","border-radius":"6px",background:"color-mix(in oklch, var(--vp-c-bg) 80%, transparent)",color:"var(--vp-c-text-1)",border:"1px solid var(--vp-c-divider)","font-weight":"500","font-size":"0.95rem","backdrop-filter":"blur(8px)"}},"GitHub",-1))])]),_:1}),s(a),e[4]||(e[4]=h('<div class="tip custom-block"><p class="custom-block-title">For designers</p><p>This whole page is the product. Three pipelines, one engine: pick hex seeds, drop an image, or edit the role schema. Whichever tab you use, the palette themes every page of the docs and persists across reloads. Hit <strong>Reset</strong> to start over.</p></div><h2 id="what-you-get" tabindex="-1">What you get <a class="header-anchor" href="#what-you-get" aria-label="Permalink to &quot;What you get&quot;">​</a></h2><p>A palette that already satisfies your accessibility requirements. Every role you ask for (<code>background</code>, <code>foreground</code>, <code>accent</code>, <code>muted</code>, or whatever your schema declares) comes out inside its declared lightness, chroma, and contrast envelope. If your seeds do not fit, the engine <strong>nudges them in OKLCH space</strong> until they do. You receive the palette that works, not a report of what is broken.</p><ul><li><strong>Variable input.</strong> 1 to 8 seed colors. Hex, RGB, HSL, OKLCH, Lab, named, or image pixels, all normalized to a canonical OKLCH-first record.</li><li><strong>Role-resolved.</strong> Pick <code>iridis-4</code>, <code>iridis-8</code>, <code>iridis-12</code>, or the full <code>iridis-16</code> schema. Or write your own role schema on the Role-schema tab above. Each tier nests inside the next, so picking a smaller tier paints with fewer tokens.</li><li><strong>Contrast-enforced.</strong> WCAG 2.1 AA or AAA, or APCA Lc. Every role pair you declare meets the threshold or the engine moves the color until it does.</li><li><strong>Framing-aware.</strong> Dark mode and light mode are real switches in the <span class="iridis-brand">iridis</span> pipeline, not a CSS toggle. Swap framing in the navbar; every role recomputes against the new envelope.</li><li><strong>Free, forever.</strong> This whole page runs in your browser. No account, no API key, no telemetry. The palette is yours.</li></ul><h2 id="when-you-actually-need-to-install-something" tabindex="-1">When you actually need to install something <a class="header-anchor" href="#when-you-actually-need-to-install-something" aria-label="Permalink to &quot;When you actually need to install something&quot;">​</a></h2><p>You only need the npm package if you want palettes generated <strong>at runtime in your app</strong>, like:</p><ul><li>Per-user theming (each user&#39;s seeds drive their session)</li><li>Dynamic responses (palette shifts on time of day, scroll, audio, sensors)</li><li>Build-step token generation in CI</li></ul><p>If you just need <em>a</em> palette, pick once, ship the result, stay here. Export, paste, ship.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes iridis iridis vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:var(--iridis-syntax-function);--shiki-dark:var(--iridis-syntax-function);">npm</span><span style="--shiki-light:var(--iridis-syntax-string);--shiki-dark:var(--iridis-syntax-string);"> install</span><span style="--shiki-light:var(--iridis-syntax-string);--shiki-dark:var(--iridis-syntax-string);"> @studnicky/iridis</span><span style="--shiki-light:var(--iridis-syntax-comment);--shiki-dark:var(--iridis-syntax-comment);">      # only if you want runtime generation</span></span></code></pre></div><h2 id="where-to-look-next" tabindex="-1">Where to look next <a class="header-anchor" href="#where-to-look-next" aria-label="Permalink to &quot;Where to look next&quot;">​</a></h2><p>For designers:</p><ul><li><strong><a href="./concepts/accessibility-calculations">Accessibility calculations</a></strong>: what AA, AAA, and APCA actually mean</li><li><strong><a href="./concepts/role-schemas">Role schemas</a></strong>: declare what a palette must satisfy</li></ul><p>For developers:</p><ul><li><strong><a href="./getting-started">Getting started</a></strong>: the one-liner, then the full Engine API</li><li><strong><a href="./concepts/pipeline">Pipeline</a></strong>: how the engine runs (intake, resolve, enforce, emit)</li><li><strong><a href="./recipes/cli">CLI</a></strong>: the same engine, no Node.js code</li><li><strong><a href="./v2-living-color">Living color (v2 thesis)</a></strong>: animation engine and reactive bindings planned next</li></ul>',14))])}const A=l(g,[["render",m]]);export{w as __pageData,A as default};
